+    const base = createTestConfig();
+    const next = createTestConfig({
+      targets: [
+        ...base.targets,
+        {
+          ...base.targets[0],
+          name: 'new-target',
+        },
+      ],
+    });
+
+    const changes = detectConfigChanges(base, next);
+
+    expect(changes.targetsAdded.map((t) => t.name)).toEqual(['new-target']);
